 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { getName, getNamespace } from '@kubevirt-utils/resources/shared';
 6	import { Button, ButtonVariant, Modal, ModalVariant } from '@patternfly/react-core';
 7	import { VMDeletionProtectionOptions } from '@virtualmachines/details/tabs/configuration/details/components/DeletionProtection/utils/types';
 8	import { setDeletionProtectionForVM } from '@virtualmachines/details/tabs/configuration/details/components/DeletionProtection/utils/utils';
 9	
10	type DeletionProtectionModalProps = {
11	  deletionProtectionOption: VMDeletionProtectionOptions;
12	  isOpen: boolean;
13	  onClose: () => void;
14	  vm: V1VirtualMachine;
15	};
16	
17	const DeletionProtectionModal: FC<DeletionProtectionModalProps> = ({
18	  deletionProtectionOption,
19	  isOpen,
20	  onClose,
21	  vm,
22	}) => {
23	  const { t } = useKubevirtTranslation();
24	  const enableDeletionProtection = deletionProtectionOption === VMDeletionProtectionOptions.ENABLE;
25	  const vmName = getName(vm);
26	  const vmNamespace = getNamespace(vm);
27	
28	  const submitHandler = () => {
29	    setDeletionProtectionForVM(vm, enableDeletionProtection);
30	    onClose();
31	  };
32	
33	  return (
34	    <Modal
35	      actions={[
36	        <Button key="confirm" onClick={submitHandler} variant={ButtonVariant.primary}>
37	          {enableDeletionProtection ? t('Enable') : t('Disable')}
38	        </Button>,
39	        <Button key="cancel" onClick={onClose} variant={ButtonVariant.link}>
40	          {t('Cancel')}
41	        </Button>,
42	      ]}
43	      title={
44	        enableDeletionProtection
45	          ? t('Enable deletion protection?')
46	          : t('Disable deletion protection?')
47	      }
48	      className="deletion-protection-modal"
49	      isOpen={isOpen}
50	      onClose={onClose}
51	      onSubmit={submitHandler}
52	      titleIconVariant="warning"
53	      variant={ModalVariant.medium}
54	    >
55	      {enableDeletionProtection ? (
56	        <>
57	          {t(
58	            'The VirtualMachine cannot be deleted if Deletion Protection is enabled to safeguard from accidental deletion. You can disable Deletion Protection at any time.',
59	          )}
60	          <br />
61	          <br />
62	          <b>
63	            {t(
64	              'Are you sure you want to enable deletion protection for {{vmName}} in {{vmNamespace}}?',
65	              { vmName, vmNamespace },
66	            )}
67	          </b>
68	        </>
69	      ) : (
70	        <>
71	          {t(
72	            'Disabling Deletion Protection will allow you to delete this VirtualMachine. VirtualMachine deletion can result in data loss or service disruption.',
73	          )}
74	          <br />
75	          <br />
76	          <b>
77	            {t(
78	              'Are you sure you want to disable deletion protection for {{vmName}} in {{vmNamespace}}?',
79	              { vmName, vmNamespace },
80	            )}
81	          </b>
82	        </>
83	      )}
84	    </Modal>
85	  );
86	};
87	
88	export default DeletionProtectionModal;

